export const dimensions = [
  {
    title: "ენერგიის წყარო (E / I)",
    intro:
      "ზომავს, საიდან იღებთ ენერგიას: ადამიანებთან ურთიერთობიდან თუ განმარტოებით, შინაგანად.",
    key: "EI",
    positive: "E",
    negative: "I",
    questions: [
      {
        text: "ხანგრძლივი სამუშაო დღის შემდეგ, თქვენთვის ენერგიის აღდგენის საუკეთესო გზაა:",
        a: { text: "ადამიანებთან ურთიერთობა", value: "E" },
        b: { text: "განმარტოება და ფიქრი", value: "I" }
      }
    ],
    descriptions: {
      E: "ენერგიას იღებთ ადამიანებთან აქტიური ურთიერთობით.",
      I: "ენერგიას იღებთ განმარტოებით და შინაგანი კონცენტრაციით."
    }
  }
];
